/* DataTables 2.0 Minimal — Finvanta CBS Offline Build */
/* Implements sorting, searching, pagination for .fv-datatable tables */
(function($){
"use strict";
if(!$ || !$.fn) return;

var DataTable = function(el, opts){
    this.el = el;
    this.opts = $.extend({paging:true,searching:true,ordering:true,pageLength:25,lengthMenu:[10,25,50,100]}, opts||{});
    this.currentPage = 0;
    this.sortCol = -1;
    this.sortDir = 'asc';
    this.filterText = '';
    this.init();
};

DataTable.prototype = {
    init: function(){
        var self = this;
        this.thead = this.el.querySelector('thead');
        this.tbody = this.el.querySelector('tbody');
        if(!this.thead || !this.tbody) return;

        this.allRows = Array.from(this.tbody.querySelectorAll('tr'));
        this.filteredRows = this.allRows.slice();
        this.wrapper = document.createElement('div');
        this.wrapper.className = 'dataTables_wrapper';
        this.el.parentNode.insertBefore(this.wrapper, this.el);
        this.wrapper.appendChild(this.el);
        this.el.classList.add('dataTable');

        // Length control
        if(this.opts.paging){
            var lenDiv = document.createElement('div');
            lenDiv.className = 'dataTables_length';
            var sel = document.createElement('select');
            this.opts.lengthMenu.forEach(function(v){var o=document.createElement('option');o.value=v;o.textContent=v;sel.appendChild(o);});
            sel.value = this.opts.pageLength;
            sel.addEventListener('change', function(){self.opts.pageLength=parseInt(this.value);self.currentPage=0;self.render();});
            lenDiv.innerHTML = 'Show ';
            lenDiv.appendChild(sel);
            lenDiv.appendChild(document.createTextNode(' records'));
            this.wrapper.insertBefore(lenDiv, this.el);
        }

        // Search
        if(this.opts.searching){
            var fDiv = document.createElement('div');
            fDiv.className = 'dataTables_filter';
            var inp = document.createElement('input');
            inp.type = 'search';
            inp.placeholder = 'Search...';
            inp.addEventListener('input', function(){self.filterText=this.value.toLowerCase();self.currentPage=0;self.applyFilter();self.render();});
            fDiv.innerHTML = 'Filter: ';
            fDiv.appendChild(inp);
            this.wrapper.insertBefore(fDiv, this.el);
        }

        // Info
        this.infoDiv = document.createElement('div');
        this.infoDiv.className = 'dataTables_info';
        this.wrapper.appendChild(this.infoDiv);

        // Pagination
        if(this.opts.paging){
            this.pagDiv = document.createElement('div');
            this.pagDiv.className = 'dataTables_paginate';
            this.wrapper.appendChild(this.pagDiv);
        }

        // Sort headers
        if(this.opts.ordering){
            var ths = this.thead.querySelectorAll('th');
            ths.forEach(function(th, idx){
                th.classList.add('sorting');
                th.addEventListener('click', function(){
                    ths.forEach(function(t){t.classList.remove('sorting_asc','sorting_desc');t.classList.add('sorting');});
                    if(self.sortCol===idx && self.sortDir==='asc'){self.sortDir='desc';th.classList.replace('sorting','sorting_desc');}
                    else{self.sortCol=idx;self.sortDir='asc';th.classList.replace('sorting','sorting_asc');}
                    self.applySort();self.render();
                });
            });
        }

        this.render();
    },

    applyFilter: function(){
        var ft = this.filterText;
        if(!ft){this.filteredRows=this.allRows.slice();return;}
        this.filteredRows = this.allRows.filter(function(r){return r.textContent.toLowerCase().indexOf(ft)!==-1;});
    },

    applySort: function(){
        var col=this.sortCol, dir=this.sortDir;
        if(col<0) return;
        this.filteredRows.sort(function(a,b){
            var at=(a.cells[col]||{}).textContent||'', bt=(b.cells[col]||{}).textContent||'';
            var an=parseFloat(at.replace(/[^0-9.-]/g,'')), bn=parseFloat(bt.replace(/[^0-9.-]/g,''));
            if(!isNaN(an)&&!isNaN(bn)) return dir==='asc'?an-bn:bn-an;
            return dir==='asc'?at.localeCompare(bt):bt.localeCompare(at);
        });
    },

    render: function(){
        var rows = this.filteredRows;
        var pl = this.opts.pageLength;
        var start = this.opts.paging ? this.currentPage * pl : 0;
        var end = this.opts.paging ? Math.min(start + pl, rows.length) : rows.length;
        var total = this.allRows.length;
        var filtered = rows.length;

        // Clear and render visible rows
        while(this.tbody.firstChild) this.tbody.removeChild(this.tbody.firstChild);
        for(var i=start;i<end;i++) this.tbody.appendChild(rows[i]);
        if(rows.length===0){
            var tr=document.createElement('tr');
            var td=document.createElement('td');
            td.setAttribute('colspan', this.thead.querySelectorAll('th').length);
            td.className='text-center text-muted';
            td.textContent='No matching records found';
            tr.appendChild(td);
            this.tbody.appendChild(tr);
        }

        // Info
        if(this.infoDiv){
            if(filtered===0) this.infoDiv.textContent='No records';
            else this.infoDiv.textContent='Showing '+(start+1)+' to '+end+' of '+filtered+(filtered!==total?' (filtered from '+total+')':'');
        }

        // Pagination
        if(this.pagDiv && this.opts.paging){
            this.pagDiv.innerHTML='';
            var pages = Math.ceil(filtered/pl);
            var self = this;
            var mkBtn = function(text, page, disabled, current){
                var a=document.createElement('a');
                a.className='paginate_button'+(disabled?' disabled':'')+(current?' current':'');
                a.textContent=text;
                a.href='#';
                if(!disabled && !current) a.addEventListener('click',function(e){e.preventDefault();self.currentPage=page;self.render();});
                else a.addEventListener('click',function(e){e.preventDefault();});
                return a;
            };
            this.pagDiv.appendChild(mkBtn('Prev', this.currentPage-1, this.currentPage===0, false));
            for(var p=0;p<pages && p<7;p++) this.pagDiv.appendChild(mkBtn(''+(p+1), p, false, p===this.currentPage));
            this.pagDiv.appendChild(mkBtn('Next', this.currentPage+1, this.currentPage>=pages-1, false));
        }
    }
};

DataTable.isDataTable = function(el){return el && el.classList && el.classList.contains('dataTable');};

// jQuery integration
$.fn.DataTable = function(opts){
    var instances = [];
    this.each(function(i, el){
        if(!DataTable.isDataTable(el)){
            instances.push(new DataTable(el, opts));
        }
    });
    return instances.length===1 ? instances[0] : instances;
};
$.fn.DataTable.isDataTable = DataTable.isDataTable;

})(typeof jQuery !== 'undefined' ? jQuery : null);
